import React from 'react';
import { Settings, User, Bell } from 'lucide-react';

const Header = ({ stats }) => {
  return (
    <div className="topbar">
      <div className="sidebar-logo">
        <span>🎓</span> Problem Bank Pro
      </div>
      
      {/* Thanh thống kê nhanh */}
      <div style={{ display: 'flex', gap: '2rem', fontSize: '0.9rem', color: '#64748b' }}>
        <div>Tổng bài: <strong style={{color: '#0f172a'}}>{stats.total || 0}</strong></div>
        <div>Chưa phân loại: <strong style={{color: '#f56565'}}>{stats.unclassified || 0}</strong></div>
        <div>Giỏ đề thi: <strong style={{color: '#3b82f6'}}>{stats.cartCount || 0}</strong></div>
        <div>Lượt sử dụng: <strong style={{color: '#10b981'}}>{stats.used || 0}</strong></div>
      </div>

      <div style={{ display: 'flex', gap: '1.5rem', alignItems: 'center', color: '#64748b' }}>
        <Bell size={20} style={{ cursor: 'pointer' }} />
        <Settings size={20} style={{ cursor: 'pointer' }} />
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer' }}>
          <User size={20} />
          <span style={{ fontWeight: 600, color: '#334155' }}>Thầy Sơn</span>
        </div>
      </div>
    </div>
  );
};

export default Header;
